def rate_limit_check(email, action='reset'):
    """Check if the email has exceeded rate limits."""
    key = f"{action}:{email}"
    now = time.time()
    hour_ago = now - 3600

    if key not in rate_limit_store:
        rate_limit_store[key] = []

    # Clean old entries
    rate_limit_store[key] = [t for t in rate_limit_store[key] if t > hour_ago]

    if len(rate_limit_store[key]) >= MAX_RESET_ATTEMPTS_PER_HOUR:
        return False

    rate_limit_store[key].append(now)
    return True


def login_required(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        if session.get('mfa_pending'):
            return jsonify({'error': 'MFA verification required'}), 403
        return f(*args, **kwargs)
    return decorated_function


def get_current_user():
    """Get the current authenticated user."""
    user_id = session.get('user_id')
    if user_id and user_id in users_db:
        return users_db[user_id]
    return None


def generate_reset_token():
    """Generate a secure reset token."""
    return secrets.token_urlsafe(48)


