@app.route('/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')
    name = data.get('name', '').strip()

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    # Check if user already exists
    for uid, user in users_db.items():
        if user['email'] == email:
            return jsonify({'error': 'Email already registered'}), 409

    user_id = secrets.token_hex(16)
    users_db[user_id] = {
        'id': user_id,
        'email': email,
        'name': name,
        'password_hash': generate_password_hash(password),
        'mfa_enabled': False,
        'mfa_secret': None,
        'mfa_backup_codes': [],
        'created_at': datetime.utcnow().isoformat(),
        'mfa_disabled_at': None,
        'mfa_reset_count': 0
    }

    return jsonify({
        'message': 'User registered successfully',
        'user_id': user_id,
        'email': email
    }), 201


@app.route('/login', methods=['POST'])
def login():
    """Authenticate a user with email and password, then check MFA."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    # Find user by email
    user = None
    for uid, u in users_db.items():
        if u['email'] == email:
            user = u
            break

    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid email or password'}), 401

    if user['mfa_enabled']:
        # Set session to indicate MFA is pending
        session['user_id'] = user['id']
        session['mfa_pending'] = True
        return jsonify({
            'message': 'Password verified. MFA verification required.',
            'mfa_required': True,
            'user_id': user['id']
        }), 200
    else:
        # No MFA, log in directly
        session['user_id'] = user['id']
        session['mfa_pending'] = False
        return jsonify({
            'message': 'Login successful',
            'mfa_required': False,
            'user_id': user['id'],
            'mfa_enabled': False,
            'mfa_recommendation': 'We recommend enabling MFA for better account security.'
        }), 200


@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    """Verify MFA TOTP code during login."""
    if 'user_id' not in session or not session.get('mfa_pending'):
        return jsonify({'error': 'No pending MFA verification'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    code = data.get('code', '').strip()
    use_backup = data.get('use_backup_code', False)

    user = users_db.get(session['user_id'])
    if not user:
        session.clear()
        return jsonify({'error': 'User not found'}), 404

    if use_backup:
        # Check backup codes
        if code in user['mfa_backup_codes']:
            user['mfa_backup_codes'].remove(code)
            session['mfa_pending'] = False
            remaining = len(user['mfa_backup_codes'])
            return jsonify({
                'message': 'Login successful (backup code used)',
                'backup_codes_remaining': remaining,
                'warning': f'You have {remaining} backup codes remaining.' if remaining <= 3 else None
            }), 200
        else:
            return jsonify({'error': 'Invalid backup code'}), 401
    else:
        # Verify TOTP
        if not user['mfa_secret']:
            return jsonify({'error': 'MFA not properly configured'}), 500

        totp = pyotp.TOTP(user['mfa_secret'])
        if totp.verify(code, valid_window=1):
            session['mfa_pending'] = False
            return jsonify({'message': 'Login successful'}), 200
        else:
            return jsonify({'error': 'Invalid MFA code'}), 401


