@app.route('/mfa/setup', methods=['POST'])
@login_required
def setup_mfa():
    """Initialize MFA setup - generate secret and QR code."""
    user = get_current_user()
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled. Disable it first to reconfigure.'}), 400

    # Generate new TOTP secret
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)

    # Generate provisioning URI for QR code
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")

    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode()

    # Store setup token temporarily
    setup_token = secrets.token_hex(16)
    mfa_setup_tokens_db[setup_token] = {
        'user_id': user['id'],
        'secret': secret,
        'created_at': time.time(),
        'expires_at': time.time() + 600  # 10 minutes
    }

    return jsonify({
        'message': 'MFA setup initiated. Scan the QR code with your authenticator app.',
        'setup_token': setup_token,
        'secret': secret,
        'qr_code': f'data:image/png;base64,{qr_base64}',
        'provisioning_uri': provisioning_uri,
        'instructions': [
            '1. Install an authenticator app (Google Authenticator, Authy, etc.)',
            '2. Scan the QR code or manually enter the secret key',
            '3. Enter the 6-digit code from the app to confirm setup',
            '4. Save your backup codes in a secure location'
        ]
    }), 200


@app.route('/mfa/confirm-setup', methods=['POST'])
@login_required
def confirm_mfa_setup():
    """Confirm MFA setup by verifying TOTP code."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    setup_token = data.get('setup_token', '')
    code = data.get('code', '').strip()

    if not setup_token or not code:
        return jsonify({'error': 'Setup token and verification code are required'}), 400

    user = get_current_user()
    if not user:
        return jsonify({'error': 'User not found'}), 404

    # Validate setup token
    setup_data = mfa_setup_tokens_db.get(setup_token)
    if not setup_data:
        return jsonify({'error': 'Invalid or expired setup token'}), 400

    if setup_data['user_id'] != user['id']:
        return jsonify({'error': 'Setup token does not match current user'}), 403

    if time.time() > setup_data['expires_at']:
        del mfa_setup_tokens_db[setup_token]
        return jsonify({'error': 'Setup token has expired. Please start setup again.'}), 400

    # Verify the TOTP code
    secret = setup_data['secret']
    totp = pyotp.TOTP(secret)

    if not totp.verify(code, valid_window=1):
        return jsonify({'error': 'Invalid verification code. Please try again.'}), 400

    # Generate backup codes
    backup_codes = [secrets.token_hex(4).upper() for _ in range(10)]

    # Enable MFA for user
    user['mfa_enabled'] = True
    user['mfa_secret'] = secret
    user['mfa_backup_codes'] = backup_codes
    user['mfa_disabled_at'] = None

    # Clean up setup token
    del mfa_setup_tokens_db[setup_token]

    return jsonify({
        'message': 'MFA has been enabled successfully!',
        'backup_codes': backup_codes,
        'warning': 'Save these backup codes in a secure location. They will not be shown again. '
                   'Each code can only be used once.'
    }), 200


@app.route('/mfa/disable', methods=['POST'])
@login_required
def disable_mfa():
    """Disable MFA for the current user (requires password confirmation)."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    password = data.get('password', '')
    code = data.get('code', '').strip()

    if not password:
        return jsonify({'error': 'Password confirmation is required'}), 400

    user = get_current_user()
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not currently enabled'}), 400

    # Verify password
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid password'}), 401

    # Verify MFA code (require current TOTP code to disable)
    if code:
        totp = pyotp.TOTP(user['mfa_secret'])
        if not totp.verify(code, valid_window=1):
            return jsonify({'error': 'Invalid MFA code'}), 401
    else:
        return jsonify({'error': 'Current MFA code is required to disable MFA'}), 400

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['mfa_disabled_at'] = datetime.utcnow().isoformat()

    # Invalidate any pending reset tokens
    invalidate_all_reset_tokens_for_user(user['id'])

    return jsonify({
        'message': 'MFA has been disabled successfully.',
        'recommendation': 'We strongly recommend re-enabling MFA for better account security.'
    }), 200


