# ============ MFA Reset (Account Recovery) ============

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Request MFA reset. Sends a reset link to the user's registered email.
    This endpoint does NOT require authentication (for account recovery).
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Rate limiting
    if not rate_limit_check(email, 'mfa_reset'):
        return jsonify({
            'error': 'Too many reset requests. Please try again later.',
            'retry_after': '1 hour'
        }), 429

    # Find user by email
    user = None
    for uid, u in users_db.items():
        if u['email'] == email:
            user = u
            break

    # Always return same response to prevent email enumeration
    generic_response = {
        'message': 'If an account with that email exists and has MFA enabled, '
                   'a reset link has been sent to the email address.',
        'note': f'The reset link will expire in {RESET_TOKEN_EXPIRY_MINUTES} minutes.'
    }

    if not user:
        # Don't reveal that the user doesn't exist
        app.logger.info(f"MFA reset requested for non-existent email: {email}")
        return jsonify(generic_response), 200

    if not user['mfa_enabled']:
        # Don't reveal MFA status
        app.logger.info(f"MFA reset requested but MFA not enabled for: {email}")
        return jsonify(generic_response), 200

    # Invalidate any existing reset tokens for this user
    invalidate_all_reset_tokens_for_user(user['id'])

    # Generate reset token
    token = generate_reset_token()
    reset_tokens_db[token] = {
        'user_id': user['id'],
        'email': email,
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': (datetime.utcnow() + timedelta(minutes=RESET_TOKEN_EXPIRY_MINUTES)).isoformat(),
        'expires_at_ts': time.time() + (RESET_TOKEN_EXPIRY_MINUTES * 60),
        'used': False,
        'ip_address': request.remote_addr,
        'user_agent': request.headers.get('User-Agent', 'unknown')
    }

    # Send reset email
    email_sent = send_reset_email(email, token)

    if not email_sent:
        app.logger.error(f"Failed to send MFA reset email to {email}")
        # Still return generic response but log the error
        # In production, you might want to retry or alert administrators

    app.logger.info(f"MFA reset token generated for user: {user['id']}")

    return jsonify(generic_response), 200


@app.route('/confirm-mfa-reset', methods=['GET'])
def confirm_mfa_reset_page():
    """
    Handle the reset link click - shows confirmation page.
    In a real app, this would render an HTML page.
    """
    token = request.args.get('token', '')

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400

    # Validate token
    token_data = reset_tokens_db.get(token)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data['used']:
        return jsonify({'error': 'This reset link has already been used'}), 400

    if time.time() > token_data['expires_at_ts']:
        del reset_tokens_db[token]
        return jsonify({'error': 'This reset link has expired'}), 400

    return jsonify({
        'message': 'Reset link is valid. Please confirm the MFA reset.',
        'token': token,
        'email': token_data['email'],
        'instructions': 'Send a POST request to /confirm-mfa-reset with the token to complete the reset.',
        'expires_at': token_data['expires_at']
    }), 200


@app.route('/confirm-mfa-reset', methods=['POST'])
def confirm_mfa_reset():
    """
    Confirm the MFA reset - disables MFA on the account.
    This is the endpoint that actually processes the reset.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    token = data.get('token', '')

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400

    # Validate token
    token_data = reset_tokens_db.get(token)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data['used']:
        return jsonify({'error': 'This reset link has already been used'}), 400

    if time.time() > token_data['expires_at_ts']:
        del reset_tokens_db[token]
        return jsonify({'error': 'This reset link has expired'}), 400

    # Find the user
    user = users_db.get(token_data['user_id'])
    if not user:
        return jsonify({'error': 'User account not found'}), 404

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['mfa_disabled_at'] = datetime.utcnow().isoformat()
    user['mfa_reset_count'] = user.get('mfa_reset_count', 0) + 1

    # Mark token as used
    token_data['used'] = True
    token_data['used_at'] = datetime.utcnow().isoformat()
    token_data['used_ip'] = request.remote_addr

    # Invalidate all other reset tokens for this user
    invalidate_all_reset_tokens_for_user(user['id'])
    # Keep the used token for audit trail
    reset_tokens_db[token] = token_data

    app.logger.info(
        f"MFA reset completed for user {user['id']} ({user['email']}) "
        f"from IP {request.remote_addr}"
    )

    # Send notification email about the reset
    try:
        notification = Message(
            subject='MFA Has Been Disabled on Your Account',
            recipients=[user['email']]
        )
        notification.body = f"""Hello {user.get('name', '')},

This is to confirm that Multi-Factor Authentication (MFA) has been disabled on your account.

Details:
- Time: {datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S UTC')}
- IP Address: {request.remote_addr}

You can now log in using just your email and password.

We strongly recommend re-enabling MFA as soon as you have access to your authenticator app.

If you did not request this change, please contact support immediately and change your password.

Best regards,
Security Team
"""
        mail.send(notification)
    except Exception as e:
        app.logger.error(f"Failed to send MFA reset notification: {str(e)}")

    return jsonify({
        'message': 'MFA has been successfully disabled on your account.',
        'email': user['email'],
        'next_steps': [
            'You can now log in with just your email and password.',
            'We strongly recommend re-enabling MFA after logging in.',
            'Go to /mfa/setup to set up MFA again.'
        ]
    }), 200


