# Cleanup task for expired tokens (in production, use a scheduled job)
@app.before_request
def cleanup_expired_tokens():
    """Periodically clean up expired tokens."""
    now = time.time()

    # Clean up expired reset tokens (keep used ones for audit)
    expired_reset = [
        token for token, data in reset_tokens_db.items()
        if not data['used'] and now > data['expires_at_ts']
    ]
    for token in expired_reset:
        del reset_tokens_db[token]

    # Clean up expired setup tokens
    expired_setup = [
        token for token, data in mfa_setup_tokens_db.items()
        if now > data['expires_at']
    ]
    for token in expired_setup:
        del mfa_setup_tokens_db[token]


